314	  // In hybrid mode, the mmap window IS the addressable RAM. Narrowing the
315	  // region to match QEMU's virt-machine layout keeps file offsets aligned
316	  // across both simulators (file[0] == GPA shared_mem_base) and lets
317	  // SimpleMemory's size-check accept a smaller-than-2.25GB external buffer.
318	  // The alias region collapses to a sentinel since QEMU virt has no mirror.
319	  constexpr uint64_t kAliasNone = 0xffffffffffffffffULL;
