385	    if (!args.elf_file.empty() && !args.continue_ctx)
386	      sim.load_elf(args.elf_file);
387	
388	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
389	    for (const auto& s: args.reset_vectors) {
390	      auto [hart, addr] = parse_reset_vector(s);
391	      if (hart) {
