393	      } else {
394	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
395	          sim.set_reset_vector(i, addr);
396	      }
397	    }
398	
399	    if (args.continue_ctx)
400	      spdlog::info("You're resuming program from the given context");
401	
402	    if (args.jtag_port)
403	      sim.init_debug_port(args.jtag_port.value());
404	
405	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx
406	        && args.resume_from_qemu.empty())
407	      throw std::runtime_error(
408	        "Required arg : program, --jtag-port, or --resume-from-qemu");
409	
410	    if (args.continue_ctx || args.save_ctx) {
411	      std::string_view s = args.context_dir;
412	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
413	        throw std::runtime_error("Error: Path " + std::string{s}
414	                                 + " exists but is not a directory.");
415	      if (!std::filesystem::exists(s)) {
416	        try {
417	          std::filesystem::create_directories(s);
418	        } catch (const std::filesystem::filesystem_error& e) {
419	          throw std::runtime_error(std::string{"Failed to create directory: "}
420	                                   + e.what());
421	        }
422	      }
423	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
424	    }
425	
426	    sim.reset();
427	
428	    if (!args.resume_from_qemu.empty())
429	      sim.apply_resume_from_qemu(args.resume_from_qemu);
430	
431	    if (!args.handoff_out.empty())
432	      sim.enable_hybrid_handoff(args.elf_file, args.handoff_out);
433	
434	    const int exit_code = sim.run();
435	
436	    sim.cpu.final();
437	
438	    if (exit_code == hybrid::kExitHandoffToQemu && !args.qemu_binary.empty()) {
439	      hybrid_state_v1 state{};
440	      std::ifstream sf(args.handoff_out, std::ios::binary);
441	      if (!sf)
442	        throw std::runtime_error("handoff: cannot read drained state file: "
443	                                 + args.handoff_out);
444	      sf.read(reinterpret_cast<char*>(&state), sizeof(state));
445	      if (!sf)
446	        throw std::runtime_error("handoff: short read of drained state file");
447	      return hybrid::run_qemu_handback(args.qemu_binary, args.elf_file, state,
448	                                       args.shared_mem_path,
449	                                       args.shared_mem_size);
450	    }
451	
452	    const auto t1 = std::chrono::steady_clock::now();
453	    const auto cycles = sim.get_cycles();
454	    spdlog::info("{} cycles simulated", cycles);
455	    if (cycles > 0) {
456	      const auto ms =
457	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
458	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
459	                   ms.count() % 1000,
460	                   double(cycles) / double(ms.count()) * 1000.0);
461	    }
462	    return exit_code;
463	  };
464	
465	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
466	
467	} catch (const std::exception& e) {
468	  spdlog::critical("fatal exception: {}\n", e.what());
469	  std::exit(EXIT_FAILURE);
470	} catch (...) {
471	  std::terminate();
472	}
