15	// Owns a host file mapped into memory and exposes it as std::span<uint8_t>.
16	// `base_gpa` records the guest physical address that file offset 0 maps to;
17	// callers that build a `MemoryRegion` over the span use this to keep the
18	// translation `addr - region.base_address` in sync with the host file layout.
19	// Default 0x80000000 matches the QEMU `virt` machine RAM base.
20	class MmapBacking
21	{
22	public:
23	  MmapBacking(const std::string& path, std::size_t size,
24	              uint64_t base_gpa = 0x80000000)
25	      : size_(size), base_gpa_(base_gpa)
26	  {
27	    fd_ = ::open(path.c_str(), O_RDWR | O_CREAT, 0600);
28	    if (fd_ < 0)
29	      throw std::runtime_error("MmapBacking: open(" + path
30	                               + ") failed: " + std::strerror(errno));
31	    if (::ftruncate(fd_, static_cast<off_t>(size_)) != 0) {
32	      auto err = std::strerror(errno);
33	      ::close(fd_);
34	      fd_ = -1;
35	      throw std::runtime_error("MmapBacking: ftruncate failed: "
36	                               + std::string{err});
37	    }
38	    // MAP_POPULATE prefaults pages so the first sweep of writes (e.g. ELF
39	    // loading) does not stall on per-page faults.
40	    void* p = ::mmap(nullptr, size_, PROT_READ | PROT_WRITE,
41	                     MAP_SHARED | MAP_POPULATE, fd_, 0);
42	    if (p == MAP_FAILED) {
43	      auto err = std::strerror(errno);
44	      ::close(fd_);
45	      fd_ = -1;
46	      throw std::runtime_error("MmapBacking: mmap failed: " + std::string{err});
47	    }
48	    base_ = static_cast<uint8_t*>(p);
49	  }
50	
51	  ~MmapBacking()
52	  {
53	    if (base_ != nullptr)
54	      ::munmap(base_, size_);
55	    if (fd_ >= 0)
56	      ::close(fd_);
57	  }
58	
59	  MmapBacking(const MmapBacking&) = delete;
60	  MmapBacking& operator=(const MmapBacking&) = delete;
61	  MmapBacking(MmapBacking&&) = delete;
62	  MmapBacking& operator=(MmapBacking&&) = delete;
63	
64	  auto span() -> std::span<uint8_t> { return {base_, size_}; }
65	  auto base_gpa() const -> uint64_t { return base_gpa_; }
66	  auto size() const -> std::size_t { return size_; }
67	
