200	  // Enables the vsim->QEMU handoff drain. After this is set, run() watches
201	  // committed PCs and on retire of a `csrw 0x7C0, *` exit-trigger drains
202	  // architectural state to `state_out_path` and returns kExitHandoffToQemu.
203	  void enable_hybrid_handoff(const std::string& elf_path,
204	                             const std::string& state_out_path)
205	  {
206	    auto elf = LIEF::ELF::Parser::parse(elf_path);
207	    if (!elf)
208	      throw std::runtime_error(
209	        "enable_hybrid_handoff: failed to parse " + elf_path);
210	
211	    hybrid::CsrTrigger trigger;
212	    for (const auto& seg: elf->segments()) {
213	      if (seg.type() != LIEF::ELF::SEGMENT_TYPES::PT_LOAD) continue;
214	      if ((static_cast<unsigned>(seg.flags()) & 1u) == 0u) continue;  // PF_X
215	      const auto content = seg.content();
216	      const std::span<const uint8_t> bytes{content.data(), content.size()};
217	      trigger.scan_buffer(bytes, seg.virtual_address());
218	    }
219	
220	    hybrid_dmi_bus_ = std::make_unique<
221	      hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width,
222	                            PLATFORM::dmi_data_width>>(platform.dmi,
223	                                                       platform.clk.period());
224	    hybrid_handoff_.emplace(std::move(trigger), *hybrid_dmi_bus_);
225	    hybrid_state_path_ = state_out_path;
226	  }
