266	  void load_image(const std::string& path, MEM_TYPE type)
267	  {
268	    switch (type) {
269	    case MEM_TYPE::ILM:
270	      if constexpr (requires { cpu.set_ilm({}); }) {
271	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
272	      } else {
273	        throw std::runtime_error(
274	          "CPU does not support ILM - cannot load ILM ROM image");
275	      }
276	      break;
277	
278	    case MEM_TYPE::DLM:
279	      if constexpr (requires { cpu.set_dlm({}); }) {
280	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
281	      } else {
282	        throw std::runtime_error(
283	          "CPU does not support DLM - cannot load DLM ROM image");
284	      }
285	      break;
286	
287	    case MEM_TYPE::RAM:
288	      read_binary_file(path, [this](const auto& data) {
289	        if (data.size() > platform.main_memory.data.size())
290	          throw std::runtime_error("RAM image size exceeds main memory size");
291	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
292	      });
293	      break;
294	
295	    default:
296	      throw std::runtime_error("Unknown memory type");
297	    }
298	  }
