300	  void reset()
301	  {
302	    static constexpr int core_num = CPU::NDS_NHART;
303	    static constexpr int reset_val = (1 << core_num) - 1;
304	
305	    platform.resetn.write(0);
306	    auto saved = context_config;
307	    context_config = {};
308	    this->run(1);
309	    context_config = saved;
310	
311	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
312	      spdlog::info("hart {} reset vector: {:#x}", i,
313	                   (uint64_t) platform.reset_vector[i].read());
314	
315	    platform.resetn.write(reset_val);
316	
317	    if (context_config.continue_from)
318	      restore_context(context_config.dir);
319	  }
