321	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
322	  {
323	    auto sa = memzeroed<struct sigaction>();
324	    sa.sa_handler = sigint_handler;
325	    sigemptyset(&sa.sa_mask);
326	
327	    auto oact = memzeroed<struct sigaction>();
328	    if (sigaction(SIGINT, &sa, &oact) == -1)
329	      perror("sigaction");
330	
331	    const auto restore_sigint = std::experimental::scope_exit{[&] {
332	      if (sigaction(SIGINT, &oact, nullptr) == -1)
333	        perror("sigaction");
334	    }};
335	
336	    // wait for debugger connections
337	    while (dtm_debug && !dtm.is_connected()) {
338	      dtm.try_accept_socket();
339	      if (ctrlc != 0) {
340	        return 130;
341	      }
342	      sleep(1);
343	    }
344	
345	    [[maybe_unused]]
346	    bool ctx_resuming = context_config.continue_from;
347	    [[maybe_unused]]
348	    bool ctx_triggered = false;
349	
350	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
351	
352	      if (ctx_resuming) [[unlikely]] {
353	        // Pull up PLIC interrupt signal at the first cycle of the resume
354	        platform.int_trigger.write(1);
355	        ctx_resuming = false;
356	        ctx_triggered = true;
357	      }
358	
359	      sc_core::sc_start(platform.clk.period());
360	
361	      trace_.on_cycle(cpu);
362	
363	      if (hybrid_handoff_) [[unlikely]] {
364	        if (auto code = check_hybrid_handoff(); code) return *code;
365	      }
366	
367	      if (trace_.pipeview_wants_exit()) {
368	        spdlog::info("Pipeline viewer requested exit (Kanata loop window complete)");
369	        return 0;
370	      }
371	
372	      if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
373	        [[unlikely]]
374	      {
375	        context_config.save(platform, cpu);
376	        spdlog::info("User save context");
377	        return 0;
378	      }
379	
380	      if (ctrlc != 0) {
381	        ctrlc = 0;
382	        spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
383	        trace_.log_committed_pcs(cpu);
384	        return 130;
385	      }
386	
387	      if (ctx_triggered) [[unlikely]] {
388	        // Pull down the interrupt signal after 1 cycle
389	        platform.int_trigger.write(0);
390	        ctx_triggered = false;
391	      }
392	
393	      if (platform.sim_control.exits >= 0) {
394	        spdlog::info("sim_control: got exit {}, stopping",
395	                     platform.sim_control.exits);
396	        spdlog::info("Exit PC: {:x}", get_current_pc());
397	        trace_.log_committed_pcs(cpu);
398	        return platform.sim_control.exits;
399	      }
400	
401	      if (this->cpu.contextp()->gotFinish())
402	        return 0;
403	
404	      spdlog::trace("PC: {:x}", get_current_pc());
405	    }
406	    return 0;
407	  }
