417	  auto check_hybrid_handoff() -> std::optional<int>
418	  {
419	    if constexpr (!requires { cpu.get_committed_pc(); }) {
420	      return std::nullopt;
421	    } else {
422	      const auto committed = cpu.get_committed_pc();
423	      if (committed.empty()) return std::nullopt;
424	      for (const auto pc: committed[0]) {
425	        auto state = hybrid_handoff_->on_retire(
426	          pc, [&](uint8_t r) -> uint64_t {
427	            if constexpr (requires { cpu.get_gpr(r); }) {
428	              return cpu.get_gpr(r);
429	            }
430	            return 0;
431	          });
432	        if (state) {
433	          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
434	                       pc, hybrid_state_path_);
435	          std::ofstream f(hybrid_state_path_, std::ios::binary);
436	          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
437	          return hybrid::kExitHandoffToQemu;
438	        }
439	      }
440	      return std::nullopt;
441	    }
442	  }
