39	inline auto pick_free_port() -> uint16_t
40	{
41	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
42	  if (s < 0)
43	    throw std::runtime_error("pick_free_port: socket");
44	
45	  sockaddr_in addr{};
46	  addr.sin_family      = AF_INET;
47	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
48	  addr.sin_port        = 0;
49	
50	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
51	    ::close(s);
52	    throw std::runtime_error("pick_free_port: bind");
53	  }
54	  socklen_t len = sizeof(addr);
55	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
56	    ::close(s);
57	    throw std::runtime_error("pick_free_port: getsockname");
58	  }
59	  ::close(s);
60	  return ntohs(addr.sin_port);
61	}
62	
63	inline auto connect_loopback(uint16_t port,
64	                             std::chrono::milliseconds timeout) -> int
65	{
66	  const auto deadline = std::chrono::steady_clock::now() + timeout;
67	  while (std::chrono::steady_clock::now() < deadline) {
68	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
69	    if (s < 0)
70	      throw std::runtime_error("connect_loopback: socket");
71	    sockaddr_in addr{};
72	    addr.sin_family      = AF_INET;
73	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
74	    addr.sin_port        = htons(port);
75	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
76	      return s;
77	    ::close(s);
78	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
79	  }
80	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
81	                           "gdbstub");
82	}
83	
84	inline auto spawn_qemu(const std::string& binary,
85	                       const std::string& elf,
86	                       uint16_t gdb_port,
87	                       const std::string& shared_mem_path = {},
88	                       uint64_t shared_mem_size = 0) -> pid_t
89	{
90	  const pid_t pid = ::fork();
91	  if (pid < 0)
92	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
93	                             + std::strerror(errno));
94	  if (pid == 0) {
95	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
96	    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
97	                              + shared_mem_path
98	                              + ",size=" + std::to_string(shared_mem_size);
99	    std::vector<const char*> argv;
100	    argv.push_back(binary.c_str());
101	    if (!shared_mem_path.empty()) {
102	      argv.push_back("-object");
103	      argv.push_back(mem_obj.c_str());
104	      argv.push_back("-machine");
105	      argv.push_back("virt,memory-backend=mem");
106	    } else {
107	      argv.push_back("-M");
108	      argv.push_back("virt");
109	    }
110	    argv.push_back("-bios");
111	    argv.push_back("none");
112	    argv.push_back("-nographic");
113	    argv.push_back("-semihosting-config");
114	    argv.push_back("enable=on,target=native");
115	    argv.push_back("-kernel");
116	    argv.push_back(elf.c_str());
117	    argv.push_back("-gdb");
118	    argv.push_back(gdb_arg.c_str());
119	    argv.push_back("-S");
120	    argv.push_back(nullptr);
121	
122	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
123	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
124	                 std::strerror(errno));
125	    ::_exit(127);
126	  }
127	  return pid;
128	}
