132	// Restores x1..x31 and PC into the QEMU vCPU via the gdbstub at `port`,
133	// then continues. Caller is responsible for waitpid().
134	inline void restore_state_via_gdbstub(uint16_t port,
135	                                      const hybrid_state_v1& state)
136	{
137	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
138	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5));
139	  spdlog::info("hybrid handback: connected, restoring state");
140	  gdbstub::Session sess{fd};
141	
142	  for (unsigned i = 1; i < 32; ++i) {
143	    auto reply = sess.send_command(gdbstub::encode_p_body(i, state.gpr[i]));
144	    if (reply != "OK")
145	      throw std::runtime_error(
146	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
147	  }
148	
149	  // RV64 GDB register layout: x0..x31 = 0..31, pc = 32.
150	  auto reply = sess.send_command(gdbstub::encode_p_body(32, state.pc));
151	  if (reply != "OK")
152	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
153	
154	  spdlog::info("hybrid handback: continuing target");
155	  sess.cont();
156	}
157	
158	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
159	// status (or 128 + signal for abnormal termination).
160	inline auto run_qemu_handback(const std::string& qemu_binary,
161	                              const std::string& elf_path,
162	                              const hybrid_state_v1& state,
163	                              const std::string& shared_mem_path = {},
164	                              uint64_t shared_mem_size = 0) -> int
165	{
166	  const auto port = detail::pick_free_port();
167	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
168	               qemu_binary, port);
169	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
170	                                       shared_mem_path, shared_mem_size);
171	
172	  try {
173	    restore_state_via_gdbstub(port, state);
174	  } catch (...) {
175	    ::kill(pid, SIGKILL);
176	    int wstat = 0;
177	    ::waitpid(pid, &wstat, 0);
178	    throw;
179	  }
180	
181	  int wstat = 0;
182	  if (::waitpid(pid, &wstat, 0) < 0)
183	    throw std::runtime_error(std::string{"waitpid: "}
184	                             + std::strerror(errno));
185	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
186	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
187	  return -1;
188	}
